FROM jsonb_to_recordset('[{"id": "cap-111-society-015", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "美國具有多樣化的氣候類型，圖(八)\n是將美國各區域與世界上其他國家\n的氣候特徵相比，把具有類似氣候\n特徵的國家標示在該區域上。臺灣\n最可能標示在圖中甲、乙、丙、丁\n何處？", "options": ["甲", "乙", "丙", ""], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 15, "raw_text": "15. 美國具有多樣化的氣候類型，圖(八)\n    是將美國各區域與世界上其他國家\n    的氣候特徵相比，把具有類似氣候\n    特徵的國家標示在該區域上。臺灣\n    最可能標示在圖中甲、乙、丙、丁\n    何處？\n    (A)甲 (B)乙 (C)丙 (D)丁                 圖(八)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-016", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "婆羅洲島分屬印尼、汶萊與馬來西亞三\n國，圖(九)為其原始森林不同時期面積的\n變化。圖中原始森林的變化趨勢與下列該\n島何種變化趨勢最為相似？", "options": ["油田開採的面積 (B)都市聚落的範圍                           圖(九)", "", "野生動物的棲地範圍", "熱帶作物的種植面積"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 16, "raw_text": "16. 婆羅洲島分屬印尼、汶萊與馬來西亞三\n    國，圖(九)為其原始森林不同時期面積的\n    變化。圖中原始森林的變化趨勢與下列該\n    島何種變化趨勢最為相似？\n    (A)油田開採的面積\n    (B)都市聚落的範圍                           圖(九)\n    (C)野生動物的棲地範圍\n    (D)熱帶作物的種植面積\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-017", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "臺灣某茶商為了提高自有茶園的茶葉產量，以供應國內日益成長的罐裝茶及手\n搖茶市場需求，且能與由越南、斯里蘭卡等產區進口的低價茶葉競爭，因而導\n入滴灌技術，精準計算用水及肥料使用量。此外，也利用農業機具栽種茶苗，\n並以無人機巡視，噴藥及採收時間則以網路平臺管理。上述各項措施，最主要\n可達到下列何種成效？", "options": ["利於傳統茶園轉型成休閒農場", "降低勞力成本占總成本的比例", "提升茶葉品質以提高單位價格", "增加出口至東協國家的茶葉量"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 17, "raw_text": "17. 臺灣某茶商為了提高自有茶園的茶葉產量，以供應國內日益成長的罐裝茶及手\n    搖茶市場需求，且能與由越南、斯里蘭卡等產區進口的低價茶葉競爭，因而導\n    入滴灌技術，精準計算用水及肥料使用量。此外，也利用農業機具栽種茶苗，\n    並以無人機巡視，噴藥及採收時間則以網路平臺管理。上述各項措施，最主要\n    可達到下列何種成效？\n    (A)利於傳統茶園轉型成休閒農場\n    (B)降低勞力成本占總成本的比例\n    (C)提升茶葉品質以提高單位價格\n    (D)增加出口至東協國家的茶葉量\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-018", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "圖 ( 十 ) 為 全 球 四 個 著 名 岬 角 的 位 置 資\n訊，其中何者位於歐 亞大陸西部海岸？", "options": ["甲", "乙", "丙", "丁 圖(十)"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 18, "raw_text": "18. 圖 ( 十 ) 為 全 球 四 個 著 名 岬 角 的 位 置 資\n    訊，其中何者位於歐 亞大陸西部海岸？\n    (A)甲             (B)乙\n    (C)丙             (D)丁\n\n                                        圖(十)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-019", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "「歷史事實」與「歷史解釋」的區別，在於歷史事實是客觀呈現過去發生的\n事件；而歷史解釋則是後人運用歷史資料，對相關歷史事件進行的詮釋與評\n價。下列敘述中，何者最適合歸類為「歷史事實」？", "options": ["甲", "乙", "丙", "丁 & 突厥：歐亞大陸上的一支游牧民族； 可汗：部分游牧民族統治者的稱號。"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 19, "raw_text": "19. 「歷史事實」與「歷史解釋」的區別，在於歷史事實是客觀呈現過去發生的\n    事件；而歷史解釋則是後人運用歷史資料，對相關歷史事件進行的詮釋與評\n    價。下列敘述中，何者最適合歸類為「歷史事實」？\n\n\n\n\n  (A)甲   (B)乙   (C)丙   (D)丁\n                                  & 突厥：歐亞大陸上的一支游牧民族；\n                                   可汗：部分游牧民族統治者的稱號。\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-020", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "圖(十一)為臺灣某年報紙刊登的二則社\n會新聞。根據內容判斷，新聞報導的\n事情最早可能發生於下列何時？", "options": ["日本統治時期", "清帝國統治時期", "中華民國政府遷臺初期", "中華民國政府推動十大建設期間 圖(十一)"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 20, "raw_text": "20. 圖(十一)為臺灣某年報紙刊登的二則社\n    會新聞。根據內容判斷，新聞報導的\n    事情最早可能發生於下列何時？\n    (A)日本統治時期\n    (B)清帝國統治時期\n    (C)中華民國政府遷臺初期\n    (D)中華民國政府推動十大建設期間\n                                          圖(十一)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-021", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "日本料理「天婦羅」，是將食材裹上澱粉漿之後下鍋油炸，這種料理源自於\n天主教徒在齋戒期間，將食材油炸後食用。在沒有冷凍技術的時代，因為油\n炸食物容易保存，所以水手於遠洋航行時也會準備油炸魚類作為糧食。葡萄\n牙的天主教徒最初到日本傳教與貿易時，同時傳入這種料理。「天婦羅」傳入\n日本的時代背景，最可能是下列何者？", "options": ["外國艦隊脅迫幕府開港，促使日本推動明治維新", "西方各國展開海外探險，建立到達東方的新航線", "日本受大唐文化的薰染，效法唐朝推動制度改革", "民主陣營為防堵共產勢力，派遣艦隊駐防太平洋"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 21, "raw_text": "21. 日本料理「天婦羅」，是將食材裹上澱粉漿之後下鍋油炸，這種料理源自於\n    天主教徒在齋戒期間，將食材油炸後食用。在沒有冷凍技術的時代，因為油\n    炸食物容易保存，所以水手於遠洋航行時也會準備油炸魚類作為糧食。葡萄\n    牙的天主教徒最初到日本傳教與貿易時，同時傳入這種料理。「天婦羅」傳入\n    日本的時代背景，最可能是下列何者？\n    (A)外國艦隊脅迫幕府開港，促使日本推動明治維新\n    (B)西方各國展開海外探險，建立到達東方的新航線\n    (C)日本受大唐文化的薰染，效法唐朝推動制度改革\n    (D)民主陣營為防堵共產勢力，派遣艦隊駐防太平洋\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-022", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "一列火車在德國官方祕密安排下，從蘇黎世出發前往俄國，車上乘客包括\n列寧及其布爾什維克黨同志，這些人曾因為反對俄國政府而流亡海外。列寧\n等人沿途經過德國、瑞典、芬蘭，最後抵達俄國的首都彼得格勒(今聖彼得\n堡)。半年後，他們領導革命，推翻臨時政府，組織新的政權，對俄國產生重\n大影響。當時德國官方安排這班列車的目的，最可能為下列何者？", "options": ["與俄國結盟對抗拿破崙", "欲緩和冷戰東西對立局勢", "遵守《德蘇互不侵犯條約》", "為使俄國退出第一次世界大戰"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 22, "raw_text": "22. 一列火車在德國官方祕密安排下，從蘇黎世出發前往俄國，車上乘客包括\n    列寧及其布爾什維克黨同志，這些人曾因為反對俄國政府而流亡海外。列寧\n    等人沿途經過德國、瑞典、芬蘭，最後抵達俄國的首都彼得格勒(今聖彼得\n    堡)。半年後，他們領導革命，推翻臨時政府，組織新的政權，對俄國產生重\n    大影響。當時德國官方安排這班列車的目的，最可能為下列何者？\n    (A)與俄國結盟對抗拿破崙\n    (B)欲緩和冷戰東西對立局勢\n    (C)遵守《德蘇互不侵犯條約》\n    (D)為使俄國退出第一次世界大戰\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-023", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "甲國政府自2019年起，要求記者須通過關於國家領袖思想的考試後，才能取\n得記者證，藉以強化他們對國家領袖的效忠。圖(十二)是近年該國政府核發記\n者證數量的變化，而表(三)則是無國界記者組織提出的全球新聞自由指數報告\n中，該國近年的排名狀況，排名越前面代表新聞自由程度越高。根據相關資\n訊判斷，關於甲國政府的此項作法，下列敘述何者最合理？\n表(三)\n時間(年)    新聞自由指數排名\n2015     全球倒數第5\n2016     全球倒數第5\n2017     全球倒數第5\n2018     全球倒數第5\n2019     全球倒數第4\n2020     全球倒數第4\n圖(十二)", "options": ["政府藉由立法規範，以保障記者的新聞自由", "政府採取獎勵政策，以促使新聞產業蓬勃發展", "政府削減新聞記者人數，以便管控媒體報導內容", "政府透過管控記者思想，以影響閱聽人接收的新聞"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 23, "raw_text": "23. 甲國政府自2019年起，要求記者須通過關於國家領袖思想的考試後，才能取\n    得記者證，藉以強化他們對國家領袖的效忠。圖(十二)是近年該國政府核發記\n    者證數量的變化，而表(三)則是無國界記者組織提出的全球新聞自由指數報告\n    中，該國近年的排名狀況，排名越前面代表新聞自由程度越高。根據相關資\n    訊判斷，關於甲國政府的此項作法，下列敘述何者最合理？\n\n                            表(三)\n                   時間(年)    新聞自由指數排名\n                    2015     全球倒數第5\n                    2016     全球倒數第5\n                    2017     全球倒數第5\n                    2018     全球倒數第5\n                    2019     全球倒數第4\n                    2020     全球倒數第4\n       圖(十二)\n  (A)政府藉由立法規範，以保障記者的新聞自由\n  (B)政府採取獎勵政策，以促使新聞產業蓬勃發展\n  (C)政府削減新聞記者人數，以便管控媒體報導內容\n  (D)政府透過管控記者思想，以影響閱聽人接收的新聞\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-024", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "表(四)呈現阿森在近三屆我國總統選舉資格的           表(四)\n變化情形。根據表中內容判斷，阿森在第14屆          總統選舉 總統選舉\n屆次\n至第15屆之間，最可能發生了下列哪一件事？          參選資格 投票資格", "options": ["被政黨開除黨籍               13     不具備   具備", "遭法院監護宣告               14     不具備   具備", "遷移戶籍至其他縣市             15     不具備  不具備", "遭法院判處褫奪公權"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 24, "raw_text": "24. 表(四)呈現阿森在近三屆我國總統選舉資格的           表(四)\n    變化情形。根據表中內容判斷，阿森在第14屆          總統選舉 總統選舉\n                            屆次\n    至第15屆之間，最可能發生了下列哪一件事？          參選資格 投票資格\n    (A)被政黨開除黨籍               13     不具備   具備\n    (B)遭法院監護宣告               14     不具備   具備\n    (C)遷移戶籍至其他縣市             15     不具備  不具備\n    (D)遭法院判處褫奪公權\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-025", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "我國國會可對中央政府部分官員的人事提名案行使同意權，並在投票表決\n前，藉由提問來審查被提名人是否適任。根據我國公職人員的法定職權判\n斷，下列哪一個問題的提問對象最可能是大法官被提名人？", "options": ["如何提升違法官員彈劾案件的辦案效率", "如何落實嚴謹審核中央政府年度總決算", "我國仍維持死刑刑罰是否違反基本人權", "公務人員的選才制度是否有改善的空間"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": [], "parse_confidence": 1.0, "original_question_number": 25, "raw_text": "25. 我國國會可對中央政府部分官員的人事提名案行使同意權，並在投票表決\n    前，藉由提問來審查被提名人是否適任。根據我國公職人員的法定職權判\n    斷，下列哪一個問題的提問對象最可能是大法官被提名人？\n    (A)如何提升違法官員彈劾案件的辦案效率\n    (B)如何落實嚴謹審核中央政府年度總決算\n    (C)我國仍維持死刑刑罰是否違反基本人權\n    (D)公務人員的選才制度是否有改善的空間\n\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-026", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "圖(十三)為某條鐵路的路線圖，該鐵路全線的海拔\n高度變化最可能為下列何者？", "options": ["", "圖(十三)", "", ""], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 26, "raw_text": "26. 圖(十三)為某條鐵路的路線圖，該鐵路全線的海拔\n    高度變化最可能為下列何者？\n    (A)         (B)\n\n\n                                                         圖(十三)\n    (C)                   (D)\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-027", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "2014年中國 吉林省與俄羅斯合作擴建圖(十四)中\n的甲港口，目前出口貨物可不經由大連港，透過\n甲港口可大幅縮短與鄰近國家部分港口的航運時\n間。擴建甲港口除上述目的外，最可能還含下列\n何優勢？", "options": ["作為俄羅斯船隻通往大西洋的出海口", "加速俄羅斯將開發重心轉向歐俄平原", "作為中、俄兩國鴨綠江流域貨物出入的港口", "提供中國船隻藉由此港口通往北極海的捷徑 圖(十四)"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image"], "parse_confidence": 0.85, "original_question_number": 27, "raw_text": "27. 2014年中國 吉林省與俄羅斯合作擴建圖(十四)中\n    的甲港口，目前出口貨物可不經由大連港，透過\n    甲港口可大幅縮短與鄰近國家部分港口的航運時\n    間。擴建甲港口除上述目的外，最可能還含下列\n    何優勢？\n    (A)作為俄羅斯船隻通往大西洋的出海口\n    (B)加速俄羅斯將開發重心轉向歐俄平原\n    (C)作為中、俄兩國鴨綠江流域貨物出入的港口\n    (D)提供中國船隻藉由此港口通往北極海的捷徑\n                                                         圖(十四)"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-111-society-028", "exam_id": "cap", "subject_id": "sub-cap-social", "paper_id": "cap-111-society", "question_type": "single_choice", "question_text": "2014年世界上只有5%的人口居住在\n圖(十五)中的深灰色區域；而相同數\n量的人口則居住在圖中黑色區域。小\n齊想要在地圖上的淺灰色區域，以圓\n圈標示另一個人口數量最相近的範\n圍，則他標示在下列何地最為適宜？", "options": ["甲", "乙", "丙", ""], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:40+00:00", "source_pdf_sha1": "017dd4352325", "answer_pdf_sha1": "5db25b41f664", "flags": ["needs_image", "option_incomplete"], "parse_confidence": 0.6, "original_question_number": 28, "raw_text": "28. 2014年世界上只有5%的人口居住在\n    圖(十五)中的深灰色區域；而相同數\n    量的人口則居住在圖中黑色區域。小\n    齊想要在地圖上的淺灰色區域，以圓\n    圈標示另一個人口數量最相近的範\n    圍，則他標示在下列何地最為適宜？\n    (A)甲         (B)乙\n    (C)丙         (D)丁                               圖(十五)\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
